  "hosts": {
    "cloudflare-dns.com": [
      "104.16.249.249",
      "104.16.248.249",
      "2606:4700::6810:f9f9",
      "2606:4700::6810:f8f9"
    ],
    "dns.google": [
      "8.8.8.8",
      "8.8.4.4",
      "2001:4860:4860::8888",
      "2001:4860:4860::8844"
    ],
    "dns.alidns.com": [
      "223.5.5.5",
      "223.6.6.6",
      "2400:3200:baba::1",
      "2400:3200::1"
    ],
    "geosite:category-ads-all": "127.255.255.255"
  },
  "servers": [
    {
      "address": "https://cloudflare-dns.com/dns-query",
      "skipFallback": false,
      "domains": [
        "geosite:geolocation-!cn"
      ],
      "expectIPs": [
        "geoip:!cn"
      ]
    },
    {
      "address": "https://dns.google/dns-query",
      "skipFallback": false
    },
    {
      "address": "https://dns.alidns.com/dns-query",
      "skipFallback": true,
      "domains": [
        "geosite:cn"
      ],
      "expectIPs": [
        "geoip:cn"
      ]
    }
  ]
}
```

