同时，sing-box中的DNS配置也有小小的缺陷，当路由规则设置为全局时，查询国内域名的IP时为直连状态。
建议匹配出站代理，将DNS查询请求路由。
以下DNS配置将在sing-box 1.11.0版本以及之后的版本中失效，之后需要对路由规则进行改动才能正确路由DNS请求。

```json
{
  "servers": [
    {
      "tag": "remote",
      "address": "8.8.8.8",
      "strategy": "prefer_ipv4",
      "detour": "proxy"
    },
    {
      "tag": "cn_direct",
      "address": "223.5.5.5",
      "strategy": "prefer_ipv4",
      "detour": "direct"
    },
    {
      "tag": "cn_proxy",
      "address": "223.5.5.5",
      "strategy": "prefer_ipv4",
      "detour": "proxy"
    },
    {
      "tag": "block",
      "address": "rcode://success"
    }
  ],
  "rules": [
    {
      "rule_set": [
        "geosite-cn"
      ],
      "outbound": "direct",
      "server": "cn_direct"
    },
    {
      "rule_set": [
        "geosite-cn"
      ],
      "outbound": "proxy",
      "server": "cn_proxy"
    },
    {
      "rule_set": [
        "geosite-category-ads-all"
      ],
      "server": "block"
